/* TODO: Implement the task-specific control policy here. */
 switch (input.kind) {
 case CONTROLLER_INPUT_LEVEL:
     controller->has_valid_sensor = true;
     controller->last_level = input.level;
     controller->last_valid_sensor_ms = input.now_ms;

     if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
         /* Low level - turn pump ON */
         controller->pump_on = true;
         controller->state = CONTROLLER_STATE_PUMPING;
     } else if (input.level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
         /* High level - turn pump OFF */
         controller->pump_on = false;
         controller->state = CONTROLLER_STATE_SAFE_OFF;
     } else {
         /* Mid-band: hold previous safe output */
         /* state remains as is, pump_on unchanged */
         if (controller->state != CONTROLLER_STATE_HOLDING) {
             controller->state = CONTROLLER_STATE_HOLDING;
         }
     }
     break;

 case CONTROLLER_INPUT_SENSOR_TIMEOUT:
 case CONTROLLER_INPUT_INVALID_LEVEL:
     /* Fault condition - fail safe to OFF */
     controller->has_valid_sensor = false;
     controller_set_safe_off(controller);
     output.timed_out = true;
     break;

 case CONTROLLER_INPUT_NONE:
 default:
     /* No new input - check timeout */
     if (controller->has_valid_sensor) {
         uint32_t elapsed = 0;
         if (input.now_ms >= controller->last_valid_sensor_ms) {
             elapsed = input.now_ms - controller->last_valid_sensor_ms;
         } else {
             /* Handle timer wraparound */
             elapsed = ((uint32_t)-1) - controller->last_valid_sensor_ms + input.now_ms + 1;
         }

         if (elapsed >= CONTROLLER_SENSOR_TIMEOUT_MS) {
             /* Timeout - fail safe to OFF */
             controller->has_valid_sensor = false;
             controller_set_safe_off(controller);
             output.timed_out = true;
         } else {
             /* Still within timeout window - hold previous state */
             if (controller->state == CONTROLLER_STATE_PUMPING) {
                 controller->state = CONTROLLER_STATE_HOLDING;
             }
         }
     } else {
         /* No valid sensor ever - stay safe off */
         controller_set_safe_off(controller);
     }
     break;
 }

